"use strict";(self.webpackChunkWon_Yong_Jo=self.webpackChunkWon_Yong_Jo||[]).push([[5296],{34503:e=>{e.exports=JSON.parse('{"label":"Near-Lossless LLM","permalink":"/docs/tags/near-lossless-llm","allTagsPath":"/docs/tags","count":1,"items":[{"id":"Paper/NLP/PEFT/Quantization/PTQ/2023-06-SpOR","title":"SpOR: A Sparse-Quantized Representation for Near-Lossless LLM Weight Compression","description":"Recent advances in large language model (LLM) pretraining \uc740 \uc778\uc0c1\uc801\uc778 \ub2a5\ub825\uc744 \uac00\uc9c4 \uace0\ud488\uc9c8 LLM \ub85c \uc774\uc5b4\uc84c\ub2e4. \uc774\ub7ec\ud55c LLM \uc744 parameter \ub2f9 3\u20134 bit \ub85c quantization \ud558\uc5ec \uc555\ucd95\ud568\uc73c\ub85c\uc368, \ub178\ud2b8\ubd81\uc774\ub098 \ubaa8\ubc14\uc77c \ud3f0\uacfc \uac19\uc740 memory \uc81c\ud55c device \uc5d0 \uc801\ud569\ud558\uac8c \ub9cc\ub4e4 \uc218 \uc788\uc73c\uba70, \uac1c\uc778\ud654\ub41c \uc0ac\uc6a9\uc744 \uac00\ub2a5\ud558\uac8c \ud55c\ub2e4. \uadf8\ub7ec\ub098 parameter \ub2f9 3\u20134 bit \ub85c\uc758 quantization \uc740 \uc77c\ubc18\uc801\uc73c\ub85c \uc911\uac04\uc5d0\uc11c \ub192\uc740 \uc218\uc900\uc758 accuracy \uc190\uc2e4\uc744 \ucd08\ub798\ud558\uba70, \ud2b9\ud788 edge deployment \uc5d0 \uc801\ud569\ud55c 1\u201310B parameter \ubc94\uc704\uc758 \uc18c\ud615 model \uc5d0\uc11c \uadf8 \uc601\ud5a5\uc774 \ud06c\ub2e4.","permalink":"/docs/Paper/NLP/PEFT/Quantization/PTQ/SpOR"}]}')}}]);